### useRef for DOM Manipulation

useRef provides direct access to DOM nodes for imperative operations. While React promotes declarative rendering, refs are necessary for certain imperative needs.

---

### Accessing DOM Nodes

```jsx
import { useRef, useEffect } from 'react';

function VideoPlayer() {
  const videoRef = useRef(null);

  useEffect(() => {
    // Access DOM node after mount
    videoRef.current.play();
  }, []);

  return <video ref={videoRef} src="video.mp4" controls />;
}
```

### Common DOM Operations

```jsx
function TextEditor() {
  const textareaRef = useRef(null);

  const insertText = (text) => {
    const textarea = textareaRef.current;
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const value = textarea.value;

    textarea.value = value.substring(0, start) + text + value.substring(end);
    textarea.focus();
    textarea.selectionStart = textarea.selectionEnd = start + text.length;
  };

  return (
    <>
      <textarea ref={textareaRef} />
      <button onClick={() => insertText('**bold**')}>Bold</button>
    </>
  );
}
```

### Measuring DOM Nodes

```jsx
function MeasureExample() {
  const divRef = useRef(null);
  const [height, setHeight] = useState(0);

  useEffect(() => {
    if (divRef.current) {
      setHeight(divRef.current.getBoundingClientRect().height);
    }
  }, []);

  return (
    <>
      <div ref={divRef}>Content</div>
      <p>Height: {height}px</p>
    </>
  );
}
```

| Operation | Code |
|-----------|------|
| Focus | `ref.current.focus()` |
| Scroll | `ref.current.scrollIntoView()` |
| Measure | `ref.current.getBoundingClientRect()` |
| Animation | `ref.current.animate()` |
| Media | `ref.current.play()`, `ref.current.pause()` |

> **Key Point:** Refs should be used sparingly for imperative DOM operations that cannot be expressed declaratively. For most UI logic, prefer state and props.

codeExample:
import { useRef } from 'react';

function ScrollToTop() {
  const listRef = useRef(null);
  const scrollToTop = () => {
    listRef.current.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div>
      <ul ref={listRef} style={{ height: 200, overflow: 'auto' }}>
        {Array.from({ length: 50 }, (_, i) => (
          <li key={i}>Item {i + 1}</li>
        ))}
      </ul>
      <button onClick={scrollToTop}>Scroll to Top</button>
    </div>
  );
}
